def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a written work into a fluent single sentence.
    Groups information by subject and builds natural clauses.
    """
    if not triples:
        return ""

    # Group triples by their subject
    subj_map: dict[str, list[Triple]] = {}
    for t in triples:
        subj_map.setdefault(t.subject, []).append(t)

    sentences: list[str] = []

